import{_ as e,H as n,f as t,i as r}from"./chunks/framework.Cvt1eIE0.js";const h=JSON.parse('{"title":"Layered是个什么项目","description":"","frontmatter":{},"headers":[],"relativePath":"summary/abstract.md","filePath":"summary/abstract.md"}'),l={name:"summary/abstract.md"};function i(o,a,d,s,m,p){return n(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="layered是个什么项目" tabindex="-1">Layered是个什么项目 <a class="header-anchor" href="#layered是个什么项目" aria-label="Permalink to &quot;Layered是个什么项目&quot;">​</a></h1><p>本项目是一个基于libclang构建的外部接口运行时，它的主要目标是把C语言，C++语言的开源项目， 以其header为基础整理为标准的C语言接口，以便于跨语言的调用。</p><h2 id="本地库相互调用的主要阻碍" tabindex="-1">本地库相互调用的主要阻碍 <a class="header-anchor" href="#本地库相互调用的主要阻碍" aria-label="Permalink to &quot;本地库相互调用的主要阻碍&quot;">​</a></h2><p>如果我们想要在另一个语言中使用本地库（例如C/C++），那么就需要获取到动态库的符号表（Symbol table）， 通过符号表我们就可以查找到想要调用的函数的内存地址，最开始C 或者类似C语言的本地语言导出的符号表非常简单， 它只包含函数的名称，但是后来随着面向对象编程逐渐 成为主流，类，接口，重载这些新概念的引入，只有函数名称对于符号表来说是不够的。</p><p>所以，这就出现了一个新概念——Mangled Name。</p><h2 id="名称混淆-name-mangling" tabindex="-1">名称混淆（Name Mangling） <a class="header-anchor" href="#名称混淆-name-mangling" aria-label="Permalink to &quot;名称混淆（Name Mangling）&quot;">​</a></h2><p>所谓的MangledName，简单来说是把其他的必要信息也整合到函数的导出名称中，例如函数的参数表 等，不同的C++编译器导出它们的规则是不同的，因此，一个库如果是使用微软的Microsoft MSVC进行编译 ，就很可能无法和使用GNU编译器的项目进行链接，因为GNU无法解析出正确的MSVC函数。</p><p>那么为什么编译器需要这样一个步骤，把名称搞成看不懂的样子呢，这其实是因为很多语言本身的特性会导致出现 不同函数使用同一个名称的问题，例如C++类的函数重载，它的函数名称是相同的，不同的只有参数，因此只导出 函数名称就会导致一个函数名称对应多个函数的情况，这就是所谓的符号冲突。</p><p>顺便一提，其他的编译型语言通常也有自己的Name Mangling规则，例如Rust，Go等，但这里不作为重点。</p><p>C语言在所有编译器中是一个例外，MSVC和GNU编译的C语言库非常通用，或者说，所有的C语言库几乎都是通用的，因为C语言 导出符号的规则非常简单，只导出函数名，没有任何额外的信息。</p><p>在MangledName之外，阻止语言之间相互调用的还有调用约定。</p><h2 id="调用约定-calling-convention" tabindex="-1">调用约定（Calling Convention） <a class="header-anchor" href="#调用约定-calling-convention" aria-label="Permalink to &quot;调用约定（Calling Convention）&quot;">​</a></h2><p>调用约定，它讲的是库函数应该如何调用，有人会感到奇怪，“什么叫函数应该如何调用”，函数的调用呢， 其实和我们印象中有所不同，一个库被加载后，我们可以得到符号表，解析符号表可以得到函数的名称以及函数的内存地址， ，如果这一种语言还有其他的东西在包含在其中（Mangled Name），那么调用的时候这些都会被解析到。</p><p>这些信息里面，最重要的就是函数的内存地址，通过这个地址，就能够调用这个函数从而实现功能，想要调用一个函数 就需要知道我们应该把参数放在哪里，按什么顺序放，调用完毕之后，这些参数应该如何清理以回收资源，而这些，就是调用 约定的内容。</p><h2 id="本项目要做什么" tabindex="-1">本项目要做什么 <a class="header-anchor" href="#本项目要做什么" aria-label="Permalink to &quot;本项目要做什么&quot;">​</a></h2><p>本项目想做的，就是想办法抹平Name Mangling和Calling Conversation等差别，把C/C++的本地库全部统一为扁平的， 基于基本类型和指针的，包含完整的Metadata的，且采用自定义的Name Mangling规则的进行查询和调用的全新外部调用体系。</p>',16)])])}const C=e(l,[["render",i]]);export{h as __pageData,C as default};
